// src/pages/OrderPage.js
import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../utils/api';
import '../components/UI.css';
import './OrderPage.css';

export default function OrderPage() {
  const { token, user } = useAuth();
  const [articles, setArticles] = useState([]);
  const [cart, setCart] = useState({}); // { articleId: quantity }
  const [note, setNote] = useState('');
  const [search, setSearch] = useState('');
  const [filterCat, setFilterCat] = useState('all');
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    api.getArticles(token)
      .then(d => setArticles(d.articles))
      .catch(e => setError(e.message))
      .finally(() => setLoading(false));
  }, [token]);

  const categories = useMemo(() => {
    const cats = [...new Set(articles.map(a => a.category))].sort();
    return cats;
  }, [articles]);

  const filtered = useMemo(() => {
    return articles.filter(a => {
      const matchCat = filterCat === 'all' || a.category === filterCat;
      const matchSearch = !search || a.name.toLowerCase().includes(search.toLowerCase()) || a.internalRef.toLowerCase().includes(search.toLowerCase());
      return matchCat && matchSearch;
    });
  }, [articles, search, filterCat]);

  const cartItems = useMemo(() =>
    Object.entries(cart)
      .filter(([, qty]) => qty > 0)
      .map(([id, qty]) => ({ article: articles.find(a => a.id === id), qty }))
      .filter(i => i.article),
    [cart, articles]
  );

  const setQty = (id, qty) => {
    setCart(prev => ({ ...prev, [id]: Math.max(0, qty) }));
  };

  const handleSubmit = async () => {
    if (cartItems.length === 0) return;
    setSubmitting(true); setError(''); setResult(null);
    try {
      const items = cartItems.map(i => ({ articleId: i.article.id, quantity: i.qty }));
      const data = await api.createOrder(token, items, note);
      setResult(data);
      setCart({}); setNote('');
    } catch (e) {
      setError(e.message);
    } finally {
      setSubmitting(false);
    }
  };

  const DEPT_LABELS = { laadpalen: 'Laadpalen', zonnepanelen: 'Zonnepanelen', all: 'Algemeen', algemeen: 'Algemeen' };

  if (loading) return (
    <div className="loading-center">
      <span className="spinner" style={{ width: 32, height: 32 }} />
      <p>Artikelen laden...</p>
    </div>
  );

  return (
    <div className="order-layout fade-in">

      {/* LEFT: Article browser */}
      <div className="article-browser">
        <div className="browser-filters">
          <input
            type="text" className="form-input" placeholder="Zoek artikel of ref..."
            value={search} onChange={e => setSearch(e.target.value)}
          />
          <select className="form-input form-select" value={filterCat} onChange={e => setFilterCat(e.target.value)}>
            <option value="all">Alle categorieën</option>
            {categories.map(c => <option key={c} value={c}>{c.charAt(0).toUpperCase() + c.slice(1)}</option>)}
          </select>
        </div>

        {filtered.length === 0 ? (
          <div className="empty-state">Geen artikelen gevonden.</div>
        ) : (
          <div className="article-list">
            {filtered.map(article => {
              const qty = cart[article.id] || 0;
              const deptKey = article.departments[0] === 'all' ? 'all' : article.departments[0];
              return (
                <div key={article.id} className={`article-card ${qty > 0 ? 'selected' : ''}`}>
                  <div className="article-info">
                    <div className="article-ref">{article.internalRef}</div>
                    <div className="article-name">{article.name}</div>
                    <div className="article-meta">
                      <span className={`badge badge-dept-${deptKey}`}>{DEPT_LABELS[deptKey] || deptKey}</span>
                      <span className="article-unit">/{article.unit}</span>
                    </div>
                  </div>
                  <div className="qty-control">
                    <button className="qty-btn" onClick={() => setQty(article.id, qty - 1)} disabled={qty === 0}>−</button>
                    <input
                      type="number" className="qty-input" value={qty || ''}
                      min="0"
                      placeholder="0"
                      onChange={e => setQty(article.id, parseInt(e.target.value) || 0)}
                    />
                    <button className="qty-btn" onClick={() => setQty(article.id, qty + 1)}>+</button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* RIGHT: Cart + submit */}
      <div className="cart-panel">
        <div className="cart-header">
          <span className="cart-title">Winkelwagen</span>
          {cartItems.length > 0 && (
            <span className="cart-count">{cartItems.length} {cartItems.length === 1 ? 'artikel' : 'artikelen'}</span>
          )}
        </div>

        {result ? (
          <div className="order-result fade-in">
            <div className="result-icon">✓</div>
            <div className="result-title">Bestelling geplaatst</div>
            {result.odooPickingName && (
              <div className="result-picking">
                Odoo picking: <strong>{result.odooPickingName}</strong>
              </div>
            )}
            {result.odooError && (
              <div className="alert alert-warning" style={{ marginTop: 12, fontSize: 13 }}>
                ⚠ Odoo fout: {result.odooError}. Bestelling wel lokaal opgeslagen.
              </div>
            )}
            <button className="btn btn-ghost" style={{ marginTop: 20, width: '100%', justifyContent: 'center' }}
              onClick={() => setResult(null)}>
              Nieuwe bestelling
            </button>
          </div>
        ) : (
          <>
            {cartItems.length === 0 ? (
              <div className="cart-empty">
                <span style={{ fontSize: 32 }}>📦</span>
                <p>Selecteer artikelen om te bestellen</p>
              </div>
            ) : (
              <div className="cart-items">
                {cartItems.map(({ article, qty }) => (
                  <div key={article.id} className="cart-item">
                    <div className="cart-item-info">
                      <div className="cart-item-name">{article.name}</div>
                      <div className="cart-item-ref">{article.internalRef}</div>
                    </div>
                    <div className="cart-item-qty">
                      <span className="qty-badge">{qty}</span>
                      <span className="cart-item-unit">{article.unit}</span>
                      <button className="remove-btn" onClick={() => setQty(article.id, 0)} title="Verwijderen">×</button>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {cartItems.length > 0 && (
              <div className="cart-footer">
                <div className="form-field">
                  <label className="form-label">Opmerking (optioneel)</label>
                  <textarea
                    className="form-input" rows={3} value={note}
                    onChange={e => setNote(e.target.value)}
                    placeholder="Bijv. dringend, voor project XYZ..."
                    style={{ resize: 'vertical' }}
                  />
                </div>
                {error && <div className="alert alert-error"><span>⚠</span> {error}</div>}
                <button
                  className="btn btn-primary"
                  style={{ width: '100%', justifyContent: 'center', padding: '13px' }}
                  onClick={handleSubmit} disabled={submitting}
                >
                  {submitting
                    ? <><span className="spinner" style={{ width: 16, height: 16 }} /> Verwerken...</>
                    : `Bestelling plaatsen (${cartItems.length})`}
                </button>
                <div className="cart-disclaimer">
                  Bestelling wordt automatisch als picking aangemaakt in Odoo.
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}
